import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.D2Ob5GRY.js";const _=JSON.parse('{"title":"注册与购买","description":"","frontmatter":{},"headers":[],"relativePath":"quickstart/register-and-buy.md","filePath":"quickstart/register-and-buy.md"}'),i={name:"quickstart/register-and-buy.md"};function o(n,a,s,h,c,d){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="注册与购买" tabindex="-1">注册与购买 <a class="header-anchor" href="#注册与购买" aria-label="Permalink to &quot;注册与购买&quot;">​</a></h1><blockquote><p>在门户网站完成账号注册与套餐购买。</p></blockquote><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><ul><li>已打开门户网站（如 <a href="https://www.linscio.com.cn" target="_blank" rel="noreferrer">https://www.linscio.com.cn</a>）。</li></ul><h2 id="在门户网站注册账号" tabindex="-1">在门户网站注册账号 <a class="header-anchor" href="#在门户网站注册账号" aria-label="Permalink to &quot;在门户网站注册账号&quot;">​</a></h2><ol><li>打开门户首页，点击「免费注册」或「登录」进入认证页。</li><li>切换到「注册」，填写用户名、密码（及可选邮箱），提交注册。</li><li>注册成功后使用同一账号登录。</li></ol><h2 id="选择并购买套餐" tabindex="-1">选择并购买套餐 <a class="header-anchor" href="#选择并购买套餐" aria-label="Permalink to &quot;选择并购买套餐&quot;">​</a></h2><p>（此处为占位：根据实际购买流程填写，如「产品介绍页选择个人版/团队版/机构版 → 支付」。）</p><h2 id="支付后账号激活说明" tabindex="-1">支付后账号激活说明 <a class="header-anchor" href="#支付后账号激活说明" aria-label="Permalink to &quot;支付后账号激活说明&quot;">​</a></h2><p>支付成功后，账号自动激活；若使用授权码路径，需在用户中心输入授权码并点击「立即激活」。</p><h2 id="登录用户中心-确认账号状态" tabindex="-1">登录用户中心，确认账号状态 <a class="header-anchor" href="#登录用户中心-确认账号状态" aria-label="Permalink to &quot;登录用户中心，确认账号状态&quot;">​</a></h2><ol><li>登录门户后点击「用户中心」。</li><li>确认「我的授权」状态为已激活，维护期至日期正确。</li><li>可在此进入「下载」页获取安装包。</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/quickstart/download.html">下载安装包</a></li><li><a href="/docs/quickstart/first-deployment.html">首次部署</a></li></ul>',14)])])}const m=e(i,[["render",o]]);export{_ as __pageData,m as default};
